      {
        "title": "Understanding Gang Culture",
        "content": "Gang culture is a complex social phenomenon characterized by loyalty, identity, and territory, often linked to criminal activities.",
        "layout": "standard"
      },
      {
        "title": "Core Characteristics",
        "content": "Key traits of gang culture include:\n- Loyalty among members\n- Strong sense of identity\n- Defined territorial boundaries\n- Engagement in criminal activities",
        "layout": "standard"
      },
      {
        "title": "Social Dynamics",
        "content": "Gang culture influences social dynamics through:\n- Group cohesion\n- Shared values and norms\n- Power struggles within and between gangs",
        "layout": "standard"
      },
      {
        "title": "Impact on Communities",
        "content": "Gang culture can significantly impact communities by:\n- Increasing crime rates\n- Creating fear among residents\n- Affecting local economies and social structures",
        "layout": "standard"
      }
    ]
  }
}
